#!/bin/bash
# ============================================================
#  BudgetPal – Linux Setup
#  Run once from the BudgetPal folder:
#    bash linux_setup.sh
#  After that, double-click the Desktop icon.
# ============================================================

SCRIPT_DIR="$( cd "$( dirname "${BASH_SOURCE[0]}" )" && pwd )"
DESKTOP="$HOME/Desktop"
APP_NAME="BudgetPal"
ICON_DIR="$HOME/.local/share/icons"
DESKTOP_FILE="$DESKTOP/$APP_NAME.desktop"
SYSTEM_DESKTOP="$HOME/.local/share/applications/$APP_NAME.desktop"
ICON_PATH="$ICON_DIR/budgetpal.png"

echo ""
echo "BudgetPal Linux Setup"
echo "====================="
echo ""

# ── 1. Install dependencies ───────────────────────────────────
echo "-> Installing dependencies..."

if command -v apt-get &>/dev/null; then
    sudo apt-get install -y python3-tk python3-openpyxl python3-pil \
        python3-pil.imagetk python3-pip 2>/dev/null || true
    # Fallback to pip if apt packages not found
    python3 -c "import openpyxl" 2>/dev/null || pip3 install openpyxl --break-system-packages 2>/dev/null || pip3 install openpyxl
    python3 -c "from PIL import ImageTk" 2>/dev/null || pip3 install pillow --break-system-packages 2>/dev/null || pip3 install pillow
else
    # Non-Debian distro fallback
    pip3 install openpyxl pillow 2>/dev/null || pip3 install openpyxl pillow --break-system-packages
fi

echo "-> Dependencies installed."

# ── 2. Write the icon PNG from embedded base64 ───────────────
mkdir -p "$ICON_DIR"
python3 - << ICON_EOF
import base64, os

B64 = ""

icon_path = "$ICON_PATH"
with open(icon_path, "wb") as f:
    f.write(base64.b64decode(B64))

try:
    from PIL import Image
    img = Image.open(icon_path).convert("RGBA")
    img = img.resize((256, 256), Image.LANCZOS)
    img.save(icon_path)
    print("Icon written.")
except Exception as e:
    print(f"Icon resize skipped: {e}")
ICON_EOF

# ── 3. Create the .desktop file on Desktop ───────────────────
mkdir -p "$DESKTOP"
mkdir -p "$HOME/.local/share/applications"

cat > "$DESKTOP_FILE" << DESKTOP_EOF
[Desktop Entry]
Version=1.0
Type=Application
Name=BudgetPal
Comment=Personal budget planner
Exec=python3 $SCRIPT_DIR/app.py
Icon=$ICON_PATH
Terminal=false
Categories=Finance;
StartupNotify=true
DESKTOP_EOF

# Also install to applications menu
cp "$DESKTOP_FILE" "$SYSTEM_DESKTOP"

# ── 4. Make it trusted/executable (GNOME requires this) ──────
chmod +x "$DESKTOP_FILE"

# Mark as trusted for Nautilus (GNOME Files)
if command -v gio &>/dev/null; then
    gio set "$DESKTOP_FILE" metadata::trusted true 2>/dev/null || true
fi

# XFCE / other DEs
if command -v xdg-desktop-icon &>/dev/null; then
    xdg-desktop-icon install --novendor "$DESKTOP_FILE" 2>/dev/null || true
fi

# Update icon cache
if command -v gtk-update-icon-cache &>/dev/null; then
    gtk-update-icon-cache "$HOME/.local/share/icons" 2>/dev/null || true
fi

# Refresh application menu
if command -v update-desktop-database &>/dev/null; then
    update-desktop-database "$HOME/.local/share/applications" 2>/dev/null || true
fi

echo ""
echo "Done!"
echo ""
echo "  A BudgetPal icon has been placed on your Desktop."
echo "  Double-click it to launch."
echo ""
echo "  If GNOME asks 'Trust and Launch' the first time,"
echo "  click that button. You only need to do it once."
echo ""
